import{_ as a,o as e,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"AIO App Attribution","description":"","frontmatter":{"title":"AIO App Attribution","slug":"aio-app-attribution"},"headers":[],"relativePath":"marketer-hub/aio-app-attribution.md","filePath":"marketer-hub/aio-app-attribution.md"}'),o={name:"marketer-hub/aio-app-attribution.md"};function n(s,t,l,c,h,d){return e(),i("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>AIO (AI Optimization) App Attribution tracks and attributes traffic from AI chat agents, including ChatGPT, Claude, Gemini, Copilot, and Perplexity. When users arrive from these AI assistants, Branch identifies the source and attributes the session correctly. AIO shows which content drove each visit and organizes AI traffic in a dedicated &quot;organic chat agent&quot; channel, giving you a complete view of how users discover your app.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>This feature is a part of SEO App Attribution. If you’ve already configured that feature, you’ll receive insights for AIO App Attribution.</p></div><h2 id="how-aio-attribution-works" tabindex="-1">How AIO Attribution works <a class="header-anchor" href="#how-aio-attribution-works" aria-label="Permalink to &quot;How AIO Attribution works&quot;">​</a></h2><ol><li><p><strong>User clicks a link from an AI chat agent</strong><br> A user asks ChatGPT, Claude, Gemini, Copilot, or Perplexity a question, and the agent shares a link to your site.</p></li><li><p><strong>Link opens in browser or webview</strong><br> The AI agent opens your link, typically with UTM parameters (like <code>utm_source=chatgpt</code>) or an identifiable referrer.</p></li><li><p><strong>Branch captures the referrer data</strong><br> When your app opens via Universal Links or App Links, the Branch SDK collects the URL, UTM parameters, and referrer information.</p></li><li><p><strong>Branch attributes the session to the AI agent</strong><br> The install, open, or event is attributed as:</p><ul><li><code>~feature</code> = &quot;organic chat agent&quot;</li><li><code>~channel</code> = ChatGPT | Claude | Gemini | Copilot | Perplexity</li><li><code>~organic_search_url</code> = the original URL the agent shared</li></ul></li></ol><p>Branch identifies each AI agent by checking UTM parameters (like <code>utm_source=chatgpt</code>) and referrer domains (like <code>chatgpt.com</code>, <code>gemini.google.com</code>, <code>perplexity.ai</code>).</p><h2 id="set-up-aio-app-attribution" tabindex="-1">Set up AIO App Attribution <a class="header-anchor" href="#set-up-aio-app-attribution" aria-label="Permalink to &quot;Set up AIO App Attribution&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Note</p><p>AIO App Attribution uses the same setup process as SEO App Attribution. If you’ve already set up SEO App Attribution, you don’t need to set up AIO separately.</p></div><p>To set up AIO App Attribution, follow the integration instructions in our <a href="https://help.branch.io/docs/seo-app-attribution#integration-guide" target="_blank" rel="noreferrer">SEO App Attribution</a> article.</p><h2 id="view-analytics" tabindex="-1">View analytics <a class="header-anchor" href="#view-analytics" aria-label="Permalink to &quot;View analytics&quot;">​</a></h2><p>You can view AIO App Attribution analytics in the <a href="./seo-app-attribution.html#6-view-analytics">legacy reporting experience</a> and the new Branch <a href="./analysis-dashboards.html">Analysis</a> reporting tool. Additionally, AIO traffic can be viewed through our <a href="https://help.branch.io/apidocs#data-apis" target="_blank" rel="noreferrer">Data APIs</a>.</p><h3 id="branch-analysis-dashboards" tabindex="-1">Branch Analysis Dashboards <a class="header-anchor" href="#branch-analysis-dashboards" aria-label="Permalink to &quot;Branch Analysis Dashboards&quot;">​</a></h3><p>In the new Branch experience, use the <a href="https://help.branch.io/docs/analysis-dashboards#dashboards" target="_blank" rel="noreferrer">Classic Suite - SEO Analytics</a> default dashboard to view both SEO and AIO analytics.</p><p>You can then use filters to:</p><ul><li>Break down traffic by channel (search engines and AI assistants)</li><li>Analyze installs, opens, purchases, and other events from both SEO and AIO</li></ul><h3 id="legacy-reporting-experience" tabindex="-1">Legacy reporting experience <a class="header-anchor" href="#legacy-reporting-experience" aria-label="Permalink to &quot;Legacy reporting experience&quot;">​</a></h3><p>View AIO analytics in the SEO section of legacy Branch. You can learn more in our <a href="./seo-app-attribution.html#6-view-analytics">SEO App Attribution</a> article.</p><h3 id="analytics-tags" tabindex="-1">Analytics tags <a class="header-anchor" href="#analytics-tags" aria-label="Permalink to &quot;Analytics tags&quot;">​</a></h3><p>Branch uses these analytic tags for AIO traffic:</p><h4 id="feature" tabindex="-1">~feature <a class="header-anchor" href="#feature" aria-label="Permalink to &quot;~feature&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Tag</th><th>Value</th><th>Data API Field</th></tr></thead><tbody><tr><td><code>~feature</code></td><td>organic chat agent</td><td><code>last_attributed_touch_data_tilde_feature</code></td></tr></tbody></table><h4 id="channel" tabindex="-1">~channel <a class="header-anchor" href="#channel" aria-label="Permalink to &quot;~channel&quot;">​</a></h4><p>The AI chat agent name:</p><ul><li>ChatGPT</li><li>Claude</li><li>Gemini</li><li>Copilot</li><li>Perplexity</li></ul><table tabindex="0"><thead><tr><th>Tag</th><th>Value</th><th>Example</th><th>Data API Field</th></tr></thead><tbody><tr><td><code>~channel</code></td><td>AI chat agent name</td><td>ChatGPT</td><td><code>last_attributed_touch_data_tilde_channel</code></td></tr></tbody></table><h4 id="organic-search-url" tabindex="-1">~organic_search_url <a class="header-anchor" href="#organic-search-url" aria-label="Permalink to &quot;~organic\\_search\\_url&quot;">​</a></h4><p>The URL the AI agent shared.</p><table tabindex="0"><thead><tr><th>Tag</th><th>Value</th><th>Example</th><th>Data API field</th></tr></thead><tbody><tr><td><code>~organic_search_url</code></td><td>Organic search URL</td><td><a href="https://example.com/category/section" target="_blank" rel="noreferrer">https://example.com/category/section</a></td><td><code>last_attributed_touch_data_tilde_organic_search_url</code></td></tr></tbody></table><p>You can use this value to identify the exact piece of content (page, article, product detail, etc.) that drove the app conversion.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Do I need to set up AIO separately from SEO App Attribution?</summary><p>No. AIO App Attribution uses the same setup as SEO App Attribution. If you&#39;ve already configured SEO App Attribution, AIO is automatically enabled and you&#39;ll start seeing AI chat agent traffic attributed without any additional setup.</p></details>',31)])])}const b=a(o,[["render",n]]);export{u as __pageData,b as default};
